{"id": "bl.oxdb", "type": "clients", "attributes": {"name": "Oxford University Research Archive", "symbol": "BL.OXDB", "year": 2010, "alternateName": "ORA", "description": "ORA (Oxford University Research Archive) is the institutional repository for the University of Oxford. ORA was established in 2007 as a permanent and secure online archive of research materials produced by members of the University of Oxford.

ORA aims to provide access to the full text of as much of Oxford's academic research as possible. This includes articles, conference papers, theses, research data, working papers, posters and more.

Making materials open access removes barriers that restrict access to research, allowing for free dissemination of full text content, available to anyone with Internet access. ORA promotes and encourages the sharing of the scholarly output produced by the members of the University of Oxford that have been published under open access conditions, whilst additionally supporting University compliance with research funder policy and assessment.", "language": ["en"], "clientType": "repository", "domains": "ora.ox.ac.uk,fairsharing.org", "re3data": "https://doi.org/10.17616/R3Q056", "opendoar": null, "issn": {}, "url": "https://ora.ox.ac.uk/", "created": "2010-12-17T14:49:58.000Z", "updated": "2024-01-29T18:29:24.000Z", "isActive": true}, "relationships": {"provider": {"data": {"id": "ylyl", "type": "providers"}}, "consortium": {"data": {"id": "BLCO", "type": "providers"}}, "prefixes": {"data": [{"id": "10.5287", "type": "prefixes"}, {"id": "10.26173", "type": "prefixes"}]}}}

{"id": "tib.ubt", "type": "clients", "attributes": {"name": "EPub Bayreuth", "symbol": "TIB.UBT", "year": 2014, "alternateName": null, "description": "EPub Bayreuth serves as the document and publication server of the University of Bayreuth. As an institutional repository, it provides the means to publish the full texts of scholarly publications of the staff members of the University of Bayreuth, offers access to the public and thus makes them searchable in various ways. Publications, which are in progress or already published (i.e. journal articles) may be placed here as well. Attention should be paid to the limits of the secondary publication right.

Since February 2014 EPub Bayreuth replaces the previous solution OPUS.

In terms of content, EPub Bayreuth's structure mirrors the organisation of the University. Authors enter the necessary data in person or by proxy after completing the log in process with their personal user id and subsequently upload the document itself. The bibliographic data of documents published on EPub Bayreuth will be automatically transferred to ERef Bayreuth, the server available for the preparation of the University's bibliography.", "language": ["de", "en"], "clientType": "repository", "domains": "uni-bayreuth.de,*.uni-bayreuth.de,doi.org", "re3data": null, "opendoar": null, "issn": {}, "url": "https://epub.uni-bayreuth.de", "created": "2014-08-19T13:04:55.000Z", "updated": "2024-03-18T08:04:12.000Z", "isActive": true}, "relationships": {"provider": {"data": {"id": "qndc", "type": "providers"}}, "consortium": {"data": {"id": "tibco", "type": "providers"}}, "prefixes": {"data": [{"id": "10.15495", "type": "prefixes"}]}}}
